import java.util.Scanner;

public class BasicIO {
    public static void main(String[] args) {
        // Storage: Create variables and Scanner
        Scanner inputReader = new Scanner(System.in);

        System.out.print("Enter first number: ");
        int number1 = inputReader.nextInt(); // Input

        System.out.print("Enter second number: ");
        int number2 = inputReader.nextInt(); // Input

        // Process: Addition logic
        int sumResult = number1 + number2;

        // Output: Print result to screen
        System.out.println("The sum is: " + sumResult);
        inputReader.close();
    } 
}

