public class ArrayMax {
    public static int findMax(int[] numbers) {
        // Input: Array 'numbers' passed as parameter

        // Storage: Initialize candidate maximum
        int maxVal = numbers[0];

        // Process: Loop and condition logic
        for (int i = 1; i < numbers.length; i++) {
            if (numbers[i] > maxVal) {
                maxVal = numbers[i];
            }
        }

        // Output: Return final result
        return maxVal;
    }
}
